            if (boletoConsulta.IdentificadorConsultaOption.IsSet)
                writer.WriteString("identificadorConsulta", boletoConsulta.IdentificadorConsulta);

            if (boletoConsulta.DescricaoInstrucaoDesconto1Option.IsSet)
                writer.WriteString("descricaoInstrucaoDesconto1", boletoConsulta.DescricaoInstrucaoDesconto1);

            if (boletoConsulta.DescricaoInstrucaoDesconto2Option.IsSet)
                writer.WriteString("descricaoInstrucaoDesconto2", boletoConsulta.DescricaoInstrucaoDesconto2);

            if (boletoConsulta.DescricaoInstrucaoDesconto3Option.IsSet)
                writer.WriteString("descricaoInstrucaoDesconto3", boletoConsulta.DescricaoInstrucaoDesconto3);

            if (boletoConsulta.MensagemBloqueioPagamentoOption.IsSet)
                writer.WriteString("mensagemBloqueioPagamento", boletoConsulta.MensagemBloqueioPagamento);
        }
    }
}
